import re
text = open('_response.md').read()
blocks = re.findall(r'```mermaid\n(.*?)```', text, re.S)
# Extract node label contents and edge label contents, check for raw breaking chars
# Node label patterns: X[...], X[(...)], X[[...]], X{...}, X((...))
# We'll pull the inner text and test.
issues = []
for i, b in enumerate(blocks):
    for ln in b.split('\n'):
        s = ln.strip()
        if not s: continue
        # find all bracketed node labels
        # cylinder [( )]
        for m in re.finditer(r'\[\((.*?)\)\]', s):
            t = m.group(1)
            bad = [c for c in t if c in '():;/"<>{}']
            if bad: issues.append((i+1, 'cylinder', t, bad, s))
        # subroutine [[ ]]
        for m in re.finditer(r'\[\[(.*?)\]\]', s):
            t = m.group(1)
            bad = [c for c in t if c in '():;/"<>{}']
            if bad: issues.append((i+1, 'subroutine', t, bad, s))
        # rhombus { }
        for m in re.finditer(r'(?<![\[\(])\{([^{}]*?)\}', s):
            t = m.group(1)
            bad = [c for c in t if c in '():;/"<>']
            if bad: issues.append((i+1, 'rhombus', t, bad, s))
        # plain rectangle [ ] (but not [( or [[ )
        for m in re.finditer(r'(?<!\[)\[(?!\[|\()([^\[\]]*?)\](?!\])', s):
            t = m.group(1)
            bad = [c for c in t if c in '():;/"<>{}']
            if bad: issues.append((i+1, 'rect', t, bad, s))
        # edge labels |"..."| -- quoted, check if quotes balanced / contain inner quote
        for m in re.finditer(r'\|"([^|]*?)"\|', s):
            t = m.group(1)
            bad = [c for c in t if c in '"']  # inner double quote would break
            if bad: issues.append((i+1, 'edge-quoted', t, bad, s))
        # unquoted edge labels |...| 
        for m in re.finditer(r'\|(?!")([^|]*?)(?<!")\|', s):
            t = m.group(1)
            bad = [c for c in t if c in '():;/"<>{}']
            if bad: issues.append((i+1, 'edge-unquoted', t, bad, s))
if issues:
    for it in issues:
        print("ISSUE:", it)
else:
    print("NO BREAKING-CHAR ISSUES FOUND in node/edge labels.")
